B.DB=new A.ls("case_003","Infant with itchy cheeks",B.jq,"A 9-month-old girl is brought to the GP with an itchy rash that has developed over the past few weeks. Her father reports she is often restless and trying to scratch her face.","Normal growth and development. Father has a history of itchy skin rashes since childhood. No known allergies.","assets/images/case_003.png",B.K8,B.If,B.Jq,B.Gj,B.IF,null)
